    packet.username = "very_long_username_that_should_work_correctly";
    packet.scores = {1, 2, 3};
    packet.metadata = "metadata with special chars: !@#$%^&*()";

    auto buffer = serialize_packet(packet);
    ASSERT_FALSE(buffer.empty());
}

