```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Write packet_id
        stream(packet_id);

        // Write username with length prefix
        stream(hexi::prefixed(username));

        // Write scores: count first, then elements using operator<<
        stream << static_cast<uint32_t>(scores.size()) << scores;

        // Write metadata as null-terminated string
        stream(hexi::null_terminated(metadata));
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create buffer to hold serialized data
    std::vector<uint8_t> buffer;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Serialize the packet using its serialise method
    const_cast<NetworkPacket&>(packet).serialise(stream);

    return buffer;
}
```

**Key implementation details:**

1. **`packet_id`**: Written directly using `stream(packet_id)`
2. **`username`**: Wrapped with `hexi::prefixed()` to add length prefix
3. **`scores`**: First writes the count as `uint32_t`, then uses `operator<<` to write the vector elements
4. **`metadata`**: Wrapped with `hexi::null_terminated()` to add null terminator
5. **`serialize_packet`**: Creates a buffer, adaptor, and stream, then calls the `serialise` method to write the packet data

