#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    std::vector<uint8_t> temp_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(temp_buffer);

    // Preview data_type without advancing read pointer
    uint8_t data_type = 0;
    adaptor.copy(&data_type, sizeof(uint8_t));

    // Check available data size
    size_t available_size = adaptor.size();

    // Now use binary_stream to read the complete data
    hexi::binary_stream stream(adaptor);

    DataResult result;
    result.data_type = data_type;

    stream >> result.data_type;

    uint32_t item_count = 0;
    stream >> item_count;

    if (data_type == 0) {
        result.int_items.reserve(item_count);
        for(uint32_t i = 0; i < item_count; ++i) {
            uint32_t value;
            stream >> value;
            result.int_items.emplace_back(value);
        }
    } else {
        result.float_items.reserve(item_count);
        for(uint32_t i = 0; i < item_count; ++i) {
            float value;
            stream >> value;
            result.float_items.emplace_back(value);
        }
    }

    return result;
}

