};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result;

    // Check minimum size (1 byte for data_type + 4 bytes for item_count)
    if (buffer.size() < sizeof(uint8_t) + sizeof(uint32_t)) {
        return result;
    }

    // Preview the first byte (data_type) without advancing the read pointer
    // Using direct buffer access for preview
    result.data_type = buffer[0];

    // Create buffer adaptor and binary stream for actual reading
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read header data
    uint8_t data_type;
    uint32_t item_count;
    stream >> data_type >> item_count;

    // Check available data size
    std::size_t header_size = sizeof(uint8_t) + sizeof(uint32_t);
    std::size_t item_size = (data_type == 0) ? sizeof(uint32_t) : sizeof(float);
    std::size_t expected_size = header_size + item_count * item_size;

    if (buffer.size() < expected_size) {
        return result; // Not enough data in buffer
    }

    // Read items based on the data type
    if (data_type == 0) {
        // Read integers
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.int_items[i];
        }
    } else if (data_type == 1) {
        // Read floats
        result.float_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.float_items[i];
        }
    }

    return result;
}
