```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Calculate required space
    // header: 4 bytes + container size: 4 bytes + items: N * 4 bytes
    size_t required_space = sizeof(uint32_t) + sizeof(uint32_t) + items.size() * sizeof(uint32_t);

    // Check available space
    size_t current_size = buffer.size();
    size_t available_space = buffer.capacity() - current_size;

    if (available_space < required_space) {
        return false; // Insufficient space
    }

    // Create buffer adaptor
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream
    hexi::binary_stream stream(adaptor);

    // Get write pointer position (seek to end of current data)
    stream.seek(current_size);

    // Write header
    stream << header;

    // Write container data
    stream.write_container(items);

    // Return true if write was successful
    return static_cast<bool>(stream);
}
```

This implementation:
1. **Checks available space**: Calculates the required space for the header (4 bytes) plus the vector (4 bytes for size + N*4 bytes for items) and compares it against available buffer capacity
2. **Gets the write pointer**: Uses `stream.seek()` to position at the end of existing data
3. **Writes container data**: Uses `stream << header` to write the header and `stream.write_container(items)` to write the vector
4. **Returns success status**: Casts the stream to bool, which returns true if the stream is in a good state (all writes succeeded)

