MessagePacket read_header_and_message(const std::span<const uint8_t> buffer) {
    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    MessagePacket packet;

    // Read the header using read method
    stream.read(packet.header);

    // Get view of remaining data using binary_stream's view method
    auto data_view = stream.view();

    // Find the null terminator
    std::size_t msg_length = 0;
    for (std::size_t i = 0; i < data_view.size(); ++i) {
        if (data_view[i] == 0) {
            msg_length = i;
            break;
        }
    }

    // Create string_view from the null-terminated message
    packet.message = std::string_view(
        reinterpret_cast<const char*>(data_view.data()),
        msg_length
    );

    return packet;
}
