#include "implementation.hpp"

TEST(BlockAllocator, FreeListManagement) {
    demonstrate_block_allocator_behavior<10>();

    // Test passes if no assertion failures occur
    EXPECT_TRUE(true);
}

TEST(BlockAllocator, ReuseFreedBlocks) {
    struct test_block {
        std::byte data[1024];
    };

    hexi::block_allocator<test_block, 5> allocator;

    std::vector<test_block*> blocks;
    for (int i = 0; i < 5; ++i) {
        blocks.push_back(allocator.allocate());
    }

    // Free all blocks
    for (auto* block : blocks) {
        allocator.deallocate(block);
    }

    // Allocate again - should reuse freed blocks
    for (int i = 0; i < 5; ++i) {
        auto* block = allocator.allocate();
        ASSERT_NE(nullptr, block);
        allocator.deallocate(block);
    }
}

