#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>
#include <algorithm>

template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(const hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_preview) {
    // Get the available data size in the buffer
    size_t available = buffer.size();

    // Limit preview to what's actually available
    size_t to_copy = std::min(bytes_to_preview, available);

    // Create result vector with appropriate capacity
    std::vector<uint8_t> result;
    result.reserve(to_copy);

    // Copy data without advancing read pointer using indexed access
    // operator[] provides const access without modifying the buffer state
    for (size_t i = 0; i < to_copy; ++i) {
        result.push_back(static_cast<uint8_t>(buffer[i]));
    }

    return result;
}

