    uint32_t test_values[] = {100, 200, 300};

    for (auto value : test_values) {
        write_uint32_to_buffer(buffer, value);
    }

    for (auto expected_value : test_values) {
        uint32_t read_value = read_uint32_from_buffer(buffer);
        EXPECT_EQ(expected_value, read_value);
    }
}

