# Complete Implementation

```cpp
#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>

using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    std::size_t bytes_written = 0;

    // Convert to unsigned to handle bit operations correctly
    using unsigned_t = std::make_unsigned_t<T>;
    unsigned_t unsigned_value = static_cast<unsigned_t>(value);

    do {
        // Extract lower 7 bits
        std::uint8_t byte = unsigned_value & 0x7F;
        unsigned_value >>= 7;

        // Set MSB if more bytes follow
        if (unsigned_value != 0) {
            byte |= 0x80;
        }

        // Write the byte
        writer << byte;
        bytes_written++;
    } while (unsigned_value != 0);

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    using unsigned_t = std::make_unsigned_t<T>;
    unsigned_t result = 0;
    int shift = 0;

    while (true) {
        std::uint8_t byte;
        reader >> byte;

        // Add the lower 7 bits to result at the appropriate position
        result |= static_cast<unsigned_t>(byte & 0x7F) << shift;

        // Check if this is the last byte (MSB is 0)
        if ((byte & 0x80) == 0) {
            break;
        }

        shift += 7;
    }

    return static_cast<T>(result);
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<std::uint8_t> buffer;

    // Encode: Create a buffer adaptor and writer
    hexi::pmc::buffer_write_adaptor<std::vector<std::uint8_t>> write_adaptor(buffer);
    hexi::pmc::binary_stream_writer writer(write_adaptor);

    // Encode the value
    encode_varint(writer, original_value);

    // Decode: Create a read adaptor and reader from the same buffer
    hexi::pmc::buffer_read_adaptor<std::vector<std::uint8_t>> read_adaptor(buffer);
    hexi::pmc::binary_stream_reader reader(read_adaptor);

    // Decode the value
    T decoded_value = decode_varint<T>(reader);

    // Verify roundtrip correctness
    return decoded_value == original_value;
}
