            auto converted_temp = hexi::endian::conditional_reverse(temp, std::endian::native, std::endian::little);
            adaptor.write(converted_temp);
        }
        auto converted_pressure = hexi::endian::conditional_reverse(pressure, std::endian::native, std::endian::little);
        adaptor.write(converted_pressure);
    }

    void serialise(auto& adaptor) {
        adaptor.read(sensor_id);
        uint32_t temp_count;
        adaptor.read(temp_count);
        temperatures.resize(temp_count);
        for (auto& temp : temperatures) {
            adaptor.read(temp);
            hexi::endian::little_to_native_inplace(temp);
        }
        adaptor.read(pressure);
        hexi::endian::little_to_native_inplace(pressure);
    }
};

The serialization method writes the sensor ID and temperature count, then converts each temperature and the pressure value to little-endian before writing. The deserialization method reads these values back and converts them from little-endian to native byte order in-place.

Helper functions wrap the serialization process: `serialize_measurement_data` creates a buffer and streams the data into it, while `deserialize_measurement_data` reconstructs the object from a buffer. The `extract_sensor_info` function uses stream utilities to read the sensor name as a view and validates bounds before reading the sensor ID.

I should include the `<bit>` header to access `std::endian` for the byte-order conversion.

